SELECT department, COUNT(staff_id) AS total_staff
FROM staffs
GROUP BY department;

SELECT t.name, AVG(ct.attendance) AS average_attendance, ct.final_grade
FROM trainers t
JOIN courses_track ct ON ct.student_id IN (
    SELECT student_id FROM courses_track WHERE course_id IN (
        SELECT course_id FROM trainers WHERE trainer_id = t.trainer_id
    )
)
WHERE ct.completed = 1 AND ct.attendance > 90
GROUP BY t.name, ct.final_grade;
